function getLevel(xp){
  let level=1;
  for(let i=1;i<XP_THRESHOLDS.length;i++){if(xp>=XP_THRESHOLDS[i])level=i+1;else break;}
  return Math.min(level,100);
}
function getXpForCurrentLevel(xp){
  const level=getLevel(xp);
  return xp-(XP_THRESHOLDS[level-1]||0);
}
function getXpNeededForNextLevel(xp){
  const level=getLevel(xp);
  if(level>=100)return 0;
  return XP_THRESHOLDS[level]-(XP_THRESHOLDS[level-1]||0);
}

