// Achievement families for tiered display
const ACH_FAMILIES=[...new Set(ACHIEVEMENTS.map(a=>a.family))];

function getRandom(ex=[],packId=null){
  const source=packId?ALL_CARDS.filter(c=>c.pack===packId):ALL_CARDS;
  const r=Math.random()*100;
  let rar=r<2.5?"Legendary":r<7.5?"Epic":r<22.5?"Rare":r<50?"Uncommon":"Common";
  let pool=source.filter(c=>c.rarity===rar&&!ex.includes(c.id));
  if(!pool.length)pool=source.filter(c=>!ex.includes(c.id));
  if(!pool.length)pool=source;
  return pool[Math.floor(Math.random()*pool.length)];
}

